// SATURDAY SCHEDULE (same as before: May 9 – Dec 12, 2026, 32 Saturdays)
// ─────────────────────────────────────────────────────────────────────────────

function saturdays(start: Date, count: number): Date[] {
  const dates: Date[] = [];
  const d = new Date(start);
  for (let i = 0; i < count; i++) {
    dates.push(new Date(d));
    d.setDate(d.getDate() + 7);
  }
  return dates;
}

const schedule: {
  date: Date; title: string; desc: string; topicIds: number[];
  type: string; classLevel: string; qCount: number; mins: number;
}[] = [];

